# 需要从浏览器 DevTools 复制 cookie
from xhs import XhsClient
from xhs.core import sign

def my_sign(uri, data=None, a1='', web_session=''):
    return sign(uri, data, a1=a1)

client = XhsClient(cookie=YOUR_COOKIE, sign=my_sign)
result = client.get_note_by_keyword('关键词', page=1)
